def check_vowel_rounding(word_afshar, word_azeri):
    # Define vowels that are typically rounded in Azerbaijani but not in Afshar
    rounded_vowels_azeri = {'ü', 'ö', 'o'}
    unrounded_vowels_afshar = {'i', 'e', 'a'}

    # Check if the word contains vowels that should differ in rounding
    for a_char, az_char in zip(word_afshar, word_azeri):
        if a_char in unrounded_vowels_afshar and az_char in rounded_vowels_azeri:
            return True
    return False

# Example usage:
afshar_word = "jiz"  # meaning 100
azeri_word = "jyz"
print(check_vowel_rounding(afshar_word, azeri_word))  # Output: False (no rounded vowels in this example)

This function compares corresponding characters in two words to detect differences in vowel rounding between Afshar and Azerbaijani.
